import React, { useState, useRef, useEffect } from 'react';

const KEYWORDS = ['if', 'return', 'buy', 'sell', 'stop_loss'];
const FUNCTIONS = ['buy', 'sell', 'position_size', 'current_price', 'sma', 'ema', 'rsi', 'macd', 'atr'];

const keywordColor = '#22C55E';
const bgColor = '#0B0F14';
const surfaceColor = '#0F1620';
const borderColor = '#1F2A37';
const textColor = '#E5E7DB';

function escapeHtml(text) {
  return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function highlightCode(code) {
  // Escape HTML
  let escaped = escapeHtml(code);

  // Regex for keywords (whole word)
  const keywordRegex = new RegExp(`\\b(${KEYWORDS.join('|')})\\b`, 'g');

  // Highlight keywords
  escaped = escaped.replace(keywordRegex, (match) => `<span style="color: ${keywordColor}; font-weight: 600;">${match}</span>`);

  return escaped;
}

function getLineNumbers(code) {
  const lines = code.split('\n').length;
  let numbers = '';
  for (let i = 1; i <= lines; i++) {
    numbers += i + '\n';
  }
  return numbers;
}

export default function ScriptEditor() {
  const [code, setCode] = useState(`// Write your trading algorithm here\n// Use print("message") to output to console\n`);
  const [highlightedCode, setHighlightedCode] = useState('');
  const [consoleOutput, setConsoleOutput] = useState('');
  const [autocompleteVisible, setAutocompleteVisible] = useState(false);
  const [autocompleteItems, setAutocompleteItems] = useState([]);
  const [autocompleteIndex, setAutocompleteIndex] = useState(0);
  const [savedScripts, setSavedScripts] = useState(() => {
    try {
      const saved = localStorage.getItem('savedScripts');
      return saved ? JSON.parse(saved) : {};
    } catch {
      return {};
    }
  });
  const [selectedScript, setSelectedScript] = useState('');

  const textareaRef = useRef(null);
  const highlightRef = useRef(null);
  const autocompleteRef = useRef(null);

  // Highlight code on code change
  useEffect(() => {
    setHighlightedCode(highlightCode(code));
  }, [code]);

  // Sync scroll of highlight div with textarea
  const onScroll = () => {
    if (highlightRef.current && textareaRef.current) {
      highlightRef.current.scrollTop = textareaRef.current.scrollTop;
      highlightRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  // Handle textarea change
  const onChange = (e) => {
    const val = e.target.value;
    setCode(val);
    updateAutocomplete(val, e.target.selectionStart);
  };

  // Update autocomplete suggestions based on current cursor position and word
  const updateAutocomplete = (text, cursorPos) => {
    // Find the current word before cursor
    const left = text.slice(0, cursorPos);
    const match = left.match(/([a-zA-Z_][a-zA-Z0-9_]*)$/);
    if (match) {
      const prefix = match[1].toLowerCase();
      const filtered = FUNCTIONS.filter(f => f.startsWith(prefix));
      if (filtered.length > 0) {
        setAutocompleteItems(filtered);
        setAutocompleteIndex(0);
        setAutocompleteVisible(true);
        return;
      }
    }
    setAutocompleteVisible(false);
  };

  // Insert autocomplete item into code
  const insertAutocomplete = (item) => {
    if (!textareaRef.current) return;
    const pos = textareaRef.current.selectionStart;
    const left = code.slice(0, pos);
    const right = code.slice(pos);
    // Replace the current word before cursor with item
    const newLeft = left.replace(/([a-zA-Z_][a-zA-Z0-9_]*)$/, item);
    const newCode = newLeft + right;
    setCode(newCode);
    setAutocompleteVisible(false);
    // Set cursor after inserted item
    setTimeout(() => {
      if (textareaRef.current) {
        textareaRef.current.focus();
        textareaRef.current.selectionStart = textareaRef.current.selectionEnd = newLeft.length;
      }
    }, 0);
  };

  // Handle keydown for autocomplete navigation and insertion
  const onKeyDown = (e) => {
    if (autocompleteVisible) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setAutocompleteIndex((i) => (i + 1) % autocompleteItems.length);
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setAutocompleteIndex((i) => (i - 1 + autocompleteItems.length) % autocompleteItems.length);
      } else if (e.key === 'Enter' || e.key === 'Tab') {
        e.preventDefault();
        insertAutocomplete(autocompleteItems[autocompleteIndex]);
      } else if (e.key === 'Escape') {
        e.preventDefault();
        setAutocompleteVisible(false);
      }
    }
  };

  // Run/backtest simulation
  const runBacktest = () => {
    // Simple simulation: parse print("...") statements and output them
    // and output a dummy backtest result
    let output = '';
    try {
      // Extract print statements
      const printRegex = /print\s*\(\s*["'`](.*?)["'`]\s*\)/g;
      let m;
      while ((m = printRegex.exec(code)) !== null) {
        output += m[1] + '\n';
      }
      // Dummy backtest result
      output += '\nBacktest Results:\n';
      output += 'Total Trades: 10\n';
      output += 'Win Rate: 60%\n';
      output += 'Profit Factor: 1.5\n';
      output += 'Net Profit: $1500\n';
    } catch (err) {
      output = 'Error during backtest: ' + err.message;
    }
    setConsoleOutput(output);
  };

  // Save current script with prompt for name
  const saveScript = () => {
    let name = prompt('Enter script name to save:', selectedScript || 'MyScript');
    if (!name) return;
    const newScripts = { ...savedScripts, [name]: code };
    setSavedScripts(newScripts);
    setSelectedScript(name);
    try {
      localStorage.setItem('savedScripts', JSON.stringify(newScripts));
    } catch {}
  };

  // Load selected script
  const loadScript = (e) => {
    const name = e.target.value;
    setSelectedScript(name);
    if (name && savedScripts[name]) {
      setCode(savedScripts[name]);
      setConsoleOutput('');
      setAutocompleteVisible(false);
    }
  };

  // Styles
  const containerStyle = {
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: bgColor,
    color: textColor,
    height: '100vh',
    display: 'flex',
    flexDirection: 'column',
    padding: 12,
    boxSizing: 'border-box',
    userSelect: 'text',
  };

  const editorWrapperStyle = {
    position: 'relative',
    flexGrow: 1,
    display: 'flex',
    border: `1px solid ${borderColor}`,
    borderRadius: 6,
    backgroundColor: surfaceColor,
    overflow: 'hidden',
    fontSize: 14,
    lineHeight: '20px',
  };

  const lineNumbersStyle = {
    padding: '8px 6px',
    backgroundColor: '#121A28',
    color: '#4B5563',
    textAlign: 'right',
    userSelect: 'none',
    fontSize: 14,
    lineHeight: '20px',
    fontFamily: "'JetBrains Mono', monospace",
  };

  const highlightStyle = {
    position: 'absolute',
    top: 0,
    left: 50,
    right: 0,
    bottom: 0,
    padding: '8px 8px',
    whiteSpace: 'pre-wrap',
    wordWrap: 'break-word',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    lineHeight: '20px',
    color: 'transparent',
    pointerEvents: 'none',
    overflow: 'hidden',
  };

  const textareaStyle = {
    position: 'relative',
    flexGrow: 1,
    marginLeft: 48,
    padding: '8px 8px',
    border: 'none',
    outline: 'none',
    resize: 'none',
    backgroundColor: 'transparent',
    color: textColor,
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    lineHeight: '20px',
    overflow: 'auto',
    whiteSpace: 'pre-wrap',
    wordWrap: 'break-word',
  };

  const autocompleteStyle = {
    position: 'absolute',
    backgroundColor: surfaceColor,
    border: `1px solid ${borderColor}`,
    borderRadius: 6,
    top: 0,
    left: 0,
    zIndex: 10,
    maxHeight: 150,
    overflowY: 'auto',
    fontSize: 14,
    fontFamily: "'JetBrains Mono', monospace",
    color: textColor,
  };

  const autocompleteItemStyle = (active) => ({
    padding: '4px 8px',
    backgroundColor: active ? '#1F2A37' : 'transparent',
    cursor: 'pointer',
  });

  const controlsStyle = {
    marginTop: 12,
    display: 'flex',
    gap: 12,
    alignItems: 'center',
  };

  const buttonStyle = {
    backgroundColor: '#22C55E',
    border: 'none',
    borderRadius: 6,
    color: bgColor,
    fontWeight: '600',
    fontSize: 14,
    padding: '6px 14px',
    cursor: 'pointer',
    userSelect: 'none',
  };

  const selectStyle = {
    backgroundColor: surfaceColor,
    border: `1px solid ${borderColor}`,
    borderRadius: 6,
    color: textColor,
    fontSize: 14,
    fontFamily: "'JetBrains Mono', monospace",
    padding: '6px 10px',
    cursor: 'pointer',
  };

  const consoleStyle = {
    marginTop: 12,
    backgroundColor: surfaceColor,
    border: `1px solid ${borderColor}`,
    borderRadius: 6,
    color: textColor,
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    lineHeight: '20px',
    padding: 12,
    whiteSpace: 'pre-wrap',
    height: 150,
    overflowY: 'auto',
  };

  // Calculate autocomplete position
  const [autocompletePos, setAutocompletePos] = useState({ top: 0, left: 0 });
  useEffect(() => {
    if (!autocompleteVisible || !textareaRef.current) return;

    const textarea = textareaRef.current;
    const selectionStart = textarea.selectionStart;

    // Create a dummy div to calculate caret position
    const div = document.createElement('div');
    const style = getComputedStyle(textarea);
    for (const prop of style) {
      div.style[prop] = style[prop];
    }
    div.style.position = 'absolute';
    div.style.visibility = 'hidden';
    div.style.whiteSpace = 'pre-wrap';
    div.style.wordWrap = 'break-word';
    div.style.width = textarea.offsetWidth + 'px';
    div.style.height = 'auto';
    div.style.overflow = 'visible';
    div.style.padding = style.padding;
    div.style.border = style.border;

    // Set text content to textarea content up to cursor
    const textBeforeCursor = code.slice(0, selectionStart);
    // Replace spaces with &nbsp; to preserve spacing
    div.textContent = textBeforeCursor;

    document.body.appendChild(div);

    // Create a span at the end to get caret position
    const span = document.createElement('span');
    span.textContent = '\u200b'; // zero width space
    div.appendChild(span);

    const rect = span.getBoundingClientRect();
    const textareaRect = textarea.getBoundingClientRect();

    const top = rect.top - textareaRect.top + textarea.scrollTop + 20; // line height offset
    const left = rect.left - textareaRect.left + textarea.scrollLeft;

    setAutocompletePos({ top, left });

    document.body.removeChild(div);
  }, [autocompleteVisible, code, autocompleteIndex]);

  return (
    <div style={containerStyle}>
      <div style={controlsStyle}>
        <select
          style={selectStyle}
          value={selectedScript}
          onChange={loadScript}
          aria-label="Load saved script"
        >
          <option value="">Load Script...</option>
          {Object.keys(savedScripts).map((name) => (
            <option key={name} value={name}>
              {name}
            </option>
          ))}
        </select>
        <button style={buttonStyle} onClick={saveScript} type="button" aria-label="Save script">
          Save Script
        </button>
        <button style={buttonStyle} onClick={runBacktest} type="button" aria-label="Run backtest">
          Run / Backtest
        </button>
      </div>
      <div style={editorWrapperStyle}>
        <pre
          aria-hidden="true"
          style={lineNumbersStyle}
        >
          {getLineNumbers(code)}
        </pre>
        <pre
          ref={highlightRef}
          aria-hidden="true"
          style={highlightStyle}
          dangerouslySetInnerHTML={{ __html: highlightedCode + '\n' }}
        />
        <textarea
          ref={textareaRef}
          spellCheck={false}
          value={code}
          onChange={onChange}
          onScroll={onScroll}
          onKeyDown={onKeyDown}
          style={textareaStyle}
          aria-label="Code editor"
        />
        {autocompleteVisible && (
          <ul
            ref={autocompleteRef}
            style={{
              ...autocompleteStyle,
              top: autocompletePos.top,
              left: autocompletePos.left + 50,
              minWidth: 140,
            }}
            role="listbox"
            aria-label="Autocomplete suggestions"
          >
            {autocompleteItems.map((item, i) => (
              <li
                key={item}
                style={autocompleteItemStyle(i === autocompleteIndex)}
                onMouseDown={(e) => {
                  e.preventDefault();
                  insertAutocomplete(item);
                }}
                role="option"
                aria-selected={i === autocompleteIndex}
              >
                {item}
              </li>
            ))}
          </ul>
        )}
      </div>
      <pre style={consoleStyle} aria-live="polite" aria-label="Console output">
        {consoleOutput || 'Console output will appear here...'}
      </pre>
    </div>
  );
}
